// Leads from node 'Fetch Unconverted Leads'
const leads = $('Fetch Unconverted Leads').first().json;
// Sent logs from node 'Fetch Sent Email Logs'
const sentLogs = $('Fetch Sent Email Logs').first().json;

const leadsArr = Array.isArray(leads) ? leads : [leads];
const logsArr = Array.isArray(sentLogs) ? sentLogs : (sentLogs ? [sentLogs] : []);

const now = Date.now();
const MINUTE = 60000;
const HOUR = 3600000;
const DAY = 86400000;

const templates = [
  { id: '15min', after: 15 * MINUTE },
  { id: '1hr',   after: 1 * HOUR },
  { id: '24hr',  after: 24 * HOUR },
  { id: '3day',  after: 3 * DAY },
  { id: '7day',  after: 7 * DAY },
  { id: '10day', after: 10 * DAY },
  { id: '15day', after: 15 * DAY },
];

const emailsToSend = [];

for (const lead of leadsArr) {
  if (!lead.email || !lead.verified_at) continue;

  const verifiedAt = new Date(lead.verified_at).getTime();
  const elapsed = now - verifiedAt;

  // Get already-sent templates for this lead
  const sentTemplates = logsArr
    .filter(l => l.email === lead.email)
    .map(l => l.template);

  // Find the next template that should be sent
  // Go through templates in order, find the first one whose time has come but hasn't been sent
  for (const t of templates) {
    if (elapsed >= t.after && !sentTemplates.includes(t.id)) {
      emailsToSend.push({
        email: lead.email,
        first_name: lead.first_name || '',
        last_name: lead.last_name || '',
        company: lead.company || '',
        plan: lead.plan || 'professional',
        billing: lead.billing || 'monthly',
        user_id: lead.user_id,
        template_id: t.id,
        verified_at: lead.verified_at
      });
      // Only send one email per lead per run
      break;
    }
  }
}

if (emailsToSend.length === 0) {
  return [{ json: { _skip: true } }];
}

return emailsToSend.map(item => ({ json: item }));

const item = $('Has Emails to Send?').first().json;
const linkResponse = $input.first().json;

const magicLink = linkResponse.properties?.action_link || linkResponse.action_link || '';
