const tpl = templates[templateId];
if (!tpl) {
  return [{ json: { _skip: true } }];
}

return [{
  json: {
    email: item.email,
    template_id: templateId,
    subject: tpl.subject,
    html: tpl.html,
    unsub_link: unsubLink,
    magic_link: magicLink
  }
}];
